func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	orderCount := len(oris)
	for jj := 0; jj < orderCount; jj++ {
		type cand struct {
			idx   int
			delta float64
		}
		var candidates []cand
		originalAssignsLen := dispatch.AssignsLen
		maxSlots := MAXASSIGNS
		if maxSlots > originalAssignsLen+orderCount-jj {
			maxSlots = originalAssignsLen + orderCount - jj
			if maxSlots > MAXASSIGNS {
				maxSlots = MAXASSIGNS
			}
		}
		evaluateSlot := func(slot int) {
			if slot >= MAXASSIGNS {
				return
			}
			oldState := dispatch.Assigns[slot]
			oldWasEmpty := oldState.StationsLen == 0
			ok := dispatch.Assigns[slot].AddShip(total_ship+jj, oris[jj], dess[jj])
			if ok {
				dispatch.Assigns[slot].GenRoute()
				delta := dispatch.Assigns[slot].Cost - oldState.Cost
				if oldWasEmpty {
					delta = dispatch.Assigns[slot].Cost
				}
				candidates = append(candidates, cand{slot, delta})
				dispatch.Assigns[slot] = oldState
				if !oldWasEmpty {
					dispatch.Assigns[slot].GenRoute()
				}
			} else {
				dispatch.Assigns[slot] = oldState
				if !oldWasEmpty {
					dispatch.Assigns[slot].GenRoute()
				}
			}
		}
		for i := 0; i < originalAssignsLen; i++ {
			evaluateSlot(i)
		}
		if len(candidates) == 0 {
			for i := originalAssignsLen; i < maxSlots; i++ {
				evaluateSlot(i)
			}
		}
		var chosenIdx int = -1
		if len(candidates) > 0 {
			bestCand := candidates[0]
			for k := 1; k < len(candidates); k++ {
				if candidates[k].delta < bestCand.delta {
					bestCand = candidates[k]
				} else if candidates[k].delta == bestCand.delta {
					secondDeltaK := 1e100
					secondDeltaB := 1e100
					if len(candidates) > 1 {
						for m := 0; m < len(candidates); m++ {
							if candidates[m].idx != candidates[k].idx {
								if candidates[m].delta < secondDeltaK {
									secondDeltaK = candidates[m].delta
								}
							}
							if candidates[m].idx != bestCand.idx {
								if candidates[m].delta < secondDeltaB {
									secondDeltaB = candidates[m].delta
								}
							}
						}
					}
					regretK := secondDeltaK - candidates[k].delta
					regretB := secondDeltaB - bestCand.delta
					if regretK > regretB {
						bestCand = candidates[k]
					}
				}
			}
			chosenIdx = bestCand.idx
		}
		inserted := false
		if chosenIdx >= 0 {
