			if ok {
				dispatch.Assigns[chosenIdx].GenRoute()
				if chosenIdx >= dispatch.AssignsLen {
					newLen := chosenIdx + 1
					if newLen > MAXASSIGNS {
						newLen = MAXASSIGNS
					}
					if dispatch.AssignsLen < newLen {
						dispatch.AssignsLen = newLen
					}
				}
				inserted = true
			}
		}
		if !inserted {
			fallbackIdx := originalAssignsLen
			for i := 0; i < MAXASSIGNS; i++ {
				if dispatch.Assigns[i].StationsLen == 0 {
					fallbackIdx = i
					break
				}
			}
			if fallbackIdx >= MAXASSIGNS {
				for i := 0; i < MAXASSIGNS; i++ {
					okfb := dispatch.Assigns[i].AddShip(total_ship+jj, oris[jj], dess[jj])
					if okfb {
						dispatch.Assigns[i].GenRoute()
						if i >= dispatch.AssignsLen {
