							}
							if dispatch.AssignsLen < newLen {
								dispatch.AssignsLen = newLen
							}
						}
						inserted = true
						break
					}
				}
				if !inserted && originalAssignsLen < MAXASSIGNS {
					fallbackIdx = originalAssignsLen
				}
			}
			if !inserted {
				ok := dispatch.Assigns[fallbackIdx].AddShip(total_ship+jj, oris[jj], dess[jj])
				if ok {
					dispatch.Assigns[fallbackIdx].GenRoute()
					if fallbackIdx >= dispatch.AssignsLen {
