						if newLen > MAXASSIGNS {
							newLen = MAXASSIGNS
						}
						if dispatch.AssignsLen < newLen {
							dispatch.AssignsLen = newLen
						}
					}
					inserted = true
				}
			}
		}
	}
	dispatch.RenewnTotalCost()
	return dispatch

