Regret‑2 insertion with dynamic penalty weighting based on station time windows and route compactness, breaking ties by weighted distance slack.}

func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	const penaltyBase = 1000.0
	const slackWeight = 0.3
	const compactnessFactor = 0.5
	penaltyMul := 1.0
	for j := range oris {
		id := total_ship + j
		type cand struct {
			idx       int
			delta     float64
			regretVal float64
		}
		var feasible []cand
		timeWindowTightness := 0.0
		if oris[j].TimeEnd-oris[j].TimeStart > 0 {
			timeWindowTightness = 1.0 / float64(oris[j].TimeEnd-oris[j].TimeStart+1)
		}
		penaltyMul = 1.0 + timeWindowTightness*compactnessFactor
		for i := 0; i < dispatch.AssignsLen; i++ {
			oldCost := dispatch.Assigns[i].Cost
			ok := dispatch.Assigns[i].AddShip(id, oris[j], dess[j])
			if ok {
				dispatch.Assigns[i].GenRoute()
				newCost := dispatch.Assigns[i].Cost
				if newCost >= 0 && newCost >= oldCost-1e-9 {
					rawDelta := newCost - oldCost
					score := rawDelta + penaltyBase*penaltyMul*(float64(i%8)/10.0)
					feasible = append(feasible, cand{i, score, 0})
				}
				dispatch.Assigns[i].RemoveShip(id)
				dispatch.Assigns[i].GenRoute()
				dispatch.Assigns[i].Cost = oldCost
			}
		}
		if len(feasible) > 1 {
			for k := 0; k < len(feasible); k++ {
				secondBest := 1e18
				for m := 0; m < len(feasible); m++ {
					if feasible[m].idx != feasible[k].idx && feasible[m].delta < secondBest {
						secondBest = feasible[m].delta
					}
				}
				regret := secondBest - feasible[k].delta
				if regret < 0 {
					regret = 0
				}
				slackPen := slackWeight * float64(cal_dis(oris[j], dess[j]))
				feasible[k].regretVal = regret + slackPen
			}
		} else if len(feasible) == 1 {
			feasible[0].regretVal = feasible[0].delta
		}
		inserted := false
		if len(feasible) > 0 {
			bestIdx := -1
			bestScore := 1e18
			for _, c := range feasible {
				val := c.regretVal
				if val < bestScore || (val == bestScore && (c.idx&(j+1))%2 == 0) {
					bestScore = val
					bestIdx = c.idx
				}
			}
			if bestIdx >= 0 {
				dispatch.Assigns[bestIdx].AddShip(id, oris[j], dess[j])
				dispatch.Assigns[bestIdx].GenRoute()
				inserted = true
			}
		}
		if !inserted {
			newIdx := dispatch.AssignsLen
			if newIdx < MAXASSIGNS {
				dispatch.Assigns[newIdx].AddShip(id, oris[j], dess[j])
				dispatch.Assigns[newIdx].GenRoute()
				dispatch.AssignsLen++
			} else {
				minPenaltyIdx := 0
				for i := 1; i < dispatch.AssignsLen; i++ {
					if dispatch.Assigns[i].Cost < dispatch.Assigns[minPenaltyIdx].Cost {
						minPenaltyIdx = i
					}
				}
				dispatch.Assigns[minPenaltyIdx].AddShip(id, oris[j], dess[j])
				dispatch.Assigns[minPenaltyIdx].GenRoute()
			}
		}
	}
	dispatch.RenewnTotalCost()
	return dispatch

