func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	const weightDelta = 1.0
	const weightPenalty = 30.0
	const minImprovement = 1e-9
	for shipID := 0; shipID < len(oris); shipID++ {
		id := total_ship + shipID
		savedCosts := make([]float64, dispatch.AssignsLen)
		for i := 0; i < dispatch.AssignsLen; i++ {
			savedCosts[i] = dispatch.Assigns[i].Cost
		}
		bestScore := 1e100
		bestIdx := -1
		feasibleFallbackIdx := -1
		fallbackDelta := 1e100
		for i := 0; i < dispatch.AssignsLen; i++ {
			assign := &dispatch.Assigns[i]
			ok := assign.AddShip(id, oris[shipID], dess[shipID])
			if !ok {
				continue
			}
			assign.GenRoute()
			newCost := assign.Cost
			delta := newCost - savedCosts[i]
			penalty := 0.0
			if newCost < 0 || delta < -1e-6 {
				penalty = 1.0
			}
			score := delta*weightDelta + penalty*weightPenalty
			if penalty == 0.0 && score < bestScore-minImprovement {
				bestScore = score
				bestIdx = i
			}
			if feasibleFallbackIdx == -1 || delta < fallbackDelta {
				feasibleFallbackIdx = i
				fallbackDelta = delta
			}
			assign.RemoveShip(id)
			assign.Cost = savedCosts[i]
			assign.GenRoute()
		}
		commitIdx := -1
		if bestIdx != -1 {
			commitIdx = bestIdx
		} else if feasibleFallbackIdx != -1 && dispatch.AssignsLen >= MAXASSIGNS {
			commitIdx = feasibleFallbackIdx
		} else if dispatch.AssignsLen < MAXASSIGNS {
			commitIdx = dispatch.AssignsLen
		} else {
			for i := 0; i < dispatch.AssignsLen; i++ {
				assign := &dispatch.Assigns[i]
				if assign.AddShip(id, oris[shipID], dess[shipID]) {
					assign.GenRoute()
					if assign.Cost >= 0 {
						commitIdx = i
						assign.RemoveShip(id)
						assign.Cost = savedCosts[i]
						assign.GenRoute()
						break
					}
					assign.RemoveShip(id)
					assign.Cost = savedCosts[i]
					assign.GenRoute()
				}
			}
			if commitIdx == -1 && dispatch.AssignsLen < MAXASSIGNS {
				commitIdx = dispatch.AssignsLen
			} else if commitIdx == -1 {
				commitIdx = feasibleFallbackIdx
			}
		}
		if commitIdx == -1 {
			if dispatch.AssignsLen < MAXASSIGNS {
				commitIdx = dispatch.AssignsLen
			} else {
				commitIdx = 0
			}
		}
		if commitIdx >= dispatch.AssignsLen {
			dispatch.AssignsLen = commitIdx + 1
		}
		dispatch.Assigns[commitIdx].AddShip(id, oris[shipID], dess[shipID])
		dispatch.Assigns[commitIdx].GenRoute()
	}
	dispatch.RenewnTotalCost()
	return dispatch

