func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	for orderIdx := 0; orderIdx < len(oris); orderIdx++ {
		type cand struct {
			idx   int
			score float64
			valid bool
		}
		var cands []cand
		for i := 0; i < dispatch.AssignsLen; i++ {
			saved := dispatch.Assigns[i]
			origCost := dispatch.Assigns[i].Cost
			if dispatch.Assigns[i].AddShip(total_ship+orderIdx, oris[orderIdx], dess[orderIdx]) {
				dispatch.Assigns[i].GenRoute()
				newCost := dispatch.Assigns[i].Cost
				if newCost >= 0 && newCost < 1e9 {
					deltaCost := newCost - origCost
					proxPenalty := cal_dis(dispatch.Assigns[i].StationCurrent, oris[orderIdx])
					oriTW := oris[orderIdx].TimeEnd - oris[orderIdx].TimeStart
					desTW := dess[orderIdx].TimeEnd - dess[orderIdx].TimeStart
					urgency := 0.0
					if oriTW > 0 && desTW > 0 {
						urgency = 20.0 / float64(oriTW+desTW+1)
					} else {
						urgency = 500000.0
					}
					score := deltaCost*0.8 + proxPenalty*0.15 + urgency*1.5
					cands = append(cands, cand{i, score, true})
				}
			}
			dispatch.Assigns[i] = saved
			dispatch.Assigns[i].GenRoute()
		}
		bestIdx := -1
		bestScore := 1e100
		secScore := 1e100
		for _, c := range cands {
			if c.score < bestScore {
				secScore = bestScore
				bestScore = c.score
				bestIdx = c.idx
			} else if c.score < secScore {
				secScore = c.score
			}
		}
		inserted := false
		if bestIdx != -1 {
			regret := secScore - bestScore
			useExisting := true
			if dispatch.AssignsLen < MAXASSIGNS {
				if regret < 0.3*bestScore && bestScore > 80000 {
					useExisting = false
				}
			}
			if useExisting {
				dispatch.Assigns[bestIdx].AddShip(total_ship+orderIdx, oris[orderIdx], dess[orderIdx])
