			savedNew := dispatch.Assigns[dispatch.AssignsLen]
			if dispatch.Assigns[dispatch.AssignsLen].AddShip(total_ship+orderIdx, oris[orderIdx], dess[orderIdx]) {
				dispatch.Assigns[dispatch.AssignsLen].GenRoute()
				if dispatch.Assigns[dispatch.AssignsLen].Cost >= 0 {
					dispatch.AssignsLen++
					inserted = true
				} else {
					dispatch.Assigns[dispatch.AssignsLen] = savedNew
					dispatch.Assigns[dispatch.AssignsLen].GenRoute()
				}
			}
		}
