Greedy insertion with parallel candidate evaluation across assigns using cost increase, proximity to current station, and time window slack, plus weighted regret-based decision between inserting into existing assign or starting a new one.}
func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	for orderIdx := 0; orderIdx < len(oris); orderIdx++ {
		type cand struct {
			idx       int
			incrCost  float64
			deltaDist float64
			timePen   float64
			ok        bool
		}
		var cands []cand
		for i := 0; i < dispatch.AssignsLen; i++ {
			saved := dispatch.Assigns[i]
			oldCost := dispatch.Assigns[i].Cost
			if dispatch.Assigns[i].AddShip(total_ship+orderIdx, oris[orderIdx], dess[orderIdx]) {
				dispatch.Assigns[i].GenRoute()
				newCost := dispatch.Assigns[i].Cost
				if newCost >= 0 {
					dd := cal_dis(dispatch.Assigns[i].StationCurrent, oris[orderIdx]) + cal_dis(oris[orderIdx], dess[orderIdx])
					tp := 0.0
					if oris[orderIdx].TimeStart > 0 || dess[orderIdx].TimeStart > 0 {
						twO := oris[orderIdx].TimeEnd - oris[orderIdx].TimeStart
						twD := dess[orderIdx].TimeEnd - dess[orderIdx].TimeStart
						if twO <= 0 || twD <= 0 {
							tp = 1e9
						} else {
							tp = 15.0 / float64(twO+twD+1)
						}
					}
					cands = append(cands, cand{i, newCost - oldCost, dd, tp, true})
				}
				dispatch.Assigns[i].RemoveShip(total_ship + orderIdx)
			}
			dispatch.Assigns[i] = saved
			dispatch.Assigns[i].GenRoute()
		}
		bestIdx := -1
		bestScore := 1e100
		secScore := 1e100
		for _, c := range cands {
			score := c.incrCost*0.65 + c.deltaDist*0.25 + c.timePen*8.0
			if score < bestScore {
				secScore = bestScore
				bestScore = score
				bestIdx = c.idx
			} else if score < secScore {
				secScore = score
			}
		}
		useExisting := false
		if bestIdx != -1 {
			regret := secScore - bestScore
			if dispatch.AssignsLen >= MAXASSIGNS || regret > 0.3*bestScore {
				useExisting = true
			}
		}
		if useExisting {
			dispatch.Assigns[bestIdx].AddShip(total_ship+orderIdx, oris[orderIdx], dess[orderIdx])
			dispatch.Assigns[bestIdx].GenRoute()
		} else {
