			if dispatch.Assigns[i].AddShip(total_ship+orderIdx, oris[orderIdx], dess[orderIdx]) {
				dispatch.Assigns[i].GenRoute()
				newCost := dispatch.Assigns[i].Cost
				if newCost >= 0 {
					dd := cal_dis(dispatch.Assigns[i].StationCurrent, oris[orderIdx]) + cal_dis(oris[orderIdx], dess[orderIdx])
					tp := 0.0
					if oris[orderIdx].TimeStart > 0 || dess[orderIdx].TimeStart > 0 {
						twO := oris[orderIdx].TimeEnd - oris[orderIdx].TimeStart
						twD := dess[orderIdx].TimeEnd - dess[orderIdx].TimeStart
						if twO <= 0 || twD <= 0 {
							tp = 1e9
						} else {
							tp = 15.0 / float64(twO+twD+1)
						}
					}
					cands = append(cands, cand{i, newCost - oldCost, dd, tp, true})
