				st2 := assign.Stations[curLen-2]
				st3 := assign.Stations[curLen-1]
				distInc = cal_dis(st1, st2) + cal_dis(st2, st3)
			}
			score := regret + beta*penalty + distInc
			if score < bestScore {
				bestScore = score
				bestIdx = i
			}
			assign.RemoveShip(id)
			assign.Cost = savedCosts[i]
			assign.GenRoute()
		}
		commitIdx := -1
		if bestIdx != -1 {
			commitIdx = bestIdx
		} else if dispatch.AssignsLen < MAXASSIGNS {
			commitIdx = dispatch.AssignsLen
		} else {
			for i := 0; i < dispatch.AssignsLen; i++ {
				assign := &dispatch.Assigns[i]
				if assign.AddShip(id, oris[shipID], dess[shipID]) {
