population.algorithm:
For each order, compute a weighted score combining insertion cost increase, time window slack penalty, and load balancing factor, then choose the feasible insertion with minimum score across existing routes and a potential new route, with forced fallback insertion ensuring all orders are placed.}
func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	const (
		timePenaltyWeight  = 0.5
		loadBalanceWeight  = 0.3
		newRouteBonus      = 50.0
		maxAcceptableScore = 1e9
	)
	type candidate struct {
		idx       int
		score     float64
		valid     bool
		oldCost   float64
		newCost   float64
	}

	for orderIdx := 0; orderIdx < len(oris); orderIdx++ {
		orderID := total_ship + orderIdx
		ori := oris[orderIdx]
		des := dess[orderIdx]

		best := candidate{idx: -1, score: maxAcceptableScore, valid: false}

		for tryIdx := 0; tryIdx <= dispatch.AssignsLen; tryIdx++ {
			if tryIdx >= MAXASSIGNS {
				continue
			}
			var assign *Assign
			if tryIdx == dispatch.AssignsLen {
				tmpAssign := Assign{}
				assign = &tmpAssign
			} else {
				assign = &dispatch.Assigns[tryIdx]
			}

			savedStation := assign.StationCurrent
			savedCost := assign.Cost

			if !assign.AddShip(orderID, ori, des) {
				continue
			}

			assign.GenRoute()
			newCost := assign.Cost
			delta := newCost - savedCost

			if newCost < 0 || delta < 0 {
				assign.RemoveShip(orderID)
				assign.StationCurrent = savedStation
				assign.Cost = savedCost
				assign.GenRoute()
				continue
			}

			timeSlackPenalty := 0.0
			if ori.TimeStart > 0 && ori.TimeEnd > ori.TimeStart {
				timeWindowWidth := float64(ori.TimeEnd - ori.TimeStart)
				if timeWindowWidth > 0 {
					midTime := (float64(ori.TimeStart) + float64(ori.TimeEnd)) / 2.0
					timeSlackPenalty = timePenaltyWeight * (midTime / timeWindowWidth)
				}
			}

			totalLoadOnAssign := 0
			for s := 0; s < assign.StationCurrent.Load; s++ {
				totalLoadOnAssign += 1
			}
			loadBalanceFactor := 0.0
			if totalLoadOnAssign > 0 {
				avgLoadPerOrder := float64(totalLoadOnAssign)
				deviation := math.Abs(float64(assign.StationCurrent.Load)-avgLoadPerOrder*0.5) / avgLoadPerOrder
				loadBalanceFactor = loadBalanceWeight * deviation
			}

			score := delta + timeSlackPenalty + loadBalanceFactor
			if tryIdx == dispatch.AssignsLen {
				score += newRouteBonus
			}

			if score < best.score {
				best.idx = tryIdx
				best.score = score
				best.valid = true
				best.oldCost = savedCost
				best.newCost = newCost
			}

			assign.RemoveShip(orderID)
			assign.StationCurrent = savedStation
			assign.Cost = savedCost
			assign.GenRoute()

			if tryIdx == dispatch.AssignsLen {
				break
			}
		}

		if best.valid {
			targetIdx := best.idx
			if targetIdx == dispatch.AssignsLen {
				if dispatch.AssignsLen < MAXASSIGNS {
					targetIdx = dispatch.AssignsLen
					dispatch.AssignsLen++
				} else {
					best.valid = false
				}
			}
			if best.valid {
				targetAssign := &dispatch.Assigns[targetIdx]
				if targetAssign.AddShip(orderID, ori, des) {
					targetAssign.GenRoute()
				} else {
					best.valid = false
				}
			}
		}

		if !best.valid {
			fallbackDone := false
			for fbIdx := 0; fbIdx < dispatch.AssignsLen && fbIdx < MAXASSIGNS; fbIdx++ {
				fbAssign := &dispatch.Assigns[fbIdx]
				if fbAssign.AddShip(orderID, ori, des) {
					fbAssign.GenRoute()
					if fbAssign.Cost >= 0 {
						fallbackDone = true
						break
					} else {
						fbAssign.RemoveShip(orderID)
						fbAssign.GenRoute()
					}
				}
			}
			if !fallbackDone {
				if dispatch.AssignsLen < MAXASSIGNS {
					newAssign := &dispatch.Assigns[dispatch.AssignsLen]
					if newAssign.AddShip(orderID, ori, des) {
						newAssign.GenRoute()
						if newAssign.Cost >= 0 {
							dispatch.AssignsLen++
						} else {
							newAssign.RemoveShip(orderID)
							newAssign.GenRoute()
						}
					}
				}
			}
		}
	}

	dispatch.RenewnTotalCost()
	return dispatch

