		des := dess[orderIdx]
		shipID := total_ship + orderIdx
		var candidates []candRecord
		maxTryIdx := currentAssignsLen
		if maxTryIdx < MAXASSIGNS {
			maxTryIdx++
		}
		for tryIdx := 0; tryIdx < maxTryIdx; tryIdx++ {
			var targetAssign *Assign
			if tryIdx >= currentAssignsLen {
				targetAssign = &dispatch.Assigns[currentAssignsLen]
			} else {
				targetAssign = &dispatch.Assigns[tryIdx]
			}
			stateBefore := *targetAssign
			ok := targetAssign.AddShip(shipID, ori, des)
			if ok {
				targetAssign.GenRoute()
				if targetAssign.Cost >= 0 {
