	type InsertionOption struct {
		assignIdx   int
		isNewAssign bool
		costDelta   float64
		feasible    bool
	}
	activeIndices := make([]int, 0, MAXASSIGNS)
	for i := 0; i < dispatch.AssignsLen; i++ {
		if dispatch.Assigns[i].StationsLen > 0 {
			activeIndices = append(activeIndices, i)
		}
	}
	for orderIdx := 0; orderIdx < len(oris); orderIdx++ {
		ori := oris[orderIdx]
		des := dess[orderIdx]
		shipID := total_ship + orderIdx
		bestOpt := InsertionOption{-1, false, 0.0, false}
		candidateIndices := make([]int, len(activeIndices))
		copy(candidateIndices, activeIndices)
		canCreateNew := dispatch.AssignsLen < MAXASSIGNS
		if canCreateNew {
			candidateIndices = append(candidateIndices, dispatch.AssignsLen)
		}
		for _, idx := range candidateIndices {
			isNew := idx >= dispatch.AssignsLen
			prevCost := 0.0
			if !isNew {
				prevCost = dispatch.Assigns[idx].Cost
			}
			inserted := dispatch.Assigns[idx].AddShip(shipID, ori, des)
			if !inserted {
				continue
			}
			dispatch.Assigns[idx].GenRoute()
			afterCost := dispatch.Assigns[idx].Cost
			delta := afterCost - prevCost
			if delta < 0 || (!bestOpt.feasible && delta >= 0) {
			}
			if !bestOpt.feasible || delta < bestOpt.costDelta {
				bestOpt.assignIdx = idx
				bestOpt.isNewAssign = isNew
				bestOpt.costDelta = delta
				bestOpt.feasible = true
			}
			dispatch.Assigns[idx].RemoveShip(shipID)
			dispatch.Assigns[idx].GenRoute()
		}
		targetIdx := bestOpt.assignIdx
		if bestOpt.feasible {
			success := dispatch.Assigns[targetIdx].AddShip(shipID, ori, des)
			if success {
				dispatch.Assigns[targetIdx].GenRoute()
				if bestOpt.isNewAssign {
