Modified regret-based insertion with time-window proximity scoring and randomized tie-breaking among top candidates.}
func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	n := len(oris)
	orderIdx := make([]int, n)
	for i := range orderIdx {
		orderIdx[i] = i
	}
	for _, oi := range orderIdx {
		type candidate struct {
			ai       int
			delta    float64
			saved    Assign
			inserted bool
		}
		var cands []candidate
		for ai := 0; ai < dispatch.AssignsLen; ai++ {
			assign := &dispatch.Assigns[ai]
			saved := *assign
			ok := assign.AddShip(total_ship+oi, oris[oi], dess[oi])
			if ok {
				assign.GenRoute()
				if assign.Cost >= 0 {
					delta := assign.Cost - saved.Cost
					cands = append(cands, candidate{ai: ai, delta: delta, saved: saved, inserted: true})
				}
			}
			assign.RemoveShip(total_ship + oi)
			*assign = saved
		}
		inserted := false
		if len(cands) > 0 {
			const kTop = 3
			topK := make([]candidate, 0, kTop)
			for _, c := range cands {
				score := c.delta
				timePenalty := 0.0
				if oris[oi].TimeStart < dess[oi].TimeStart {
					midT := (oris[oi].TimeStart + dess[oi].TimeStart) / 2
					twPenalty := float64(midT-dispatch.Assigns[c.ai].StationCurrent.TimeStart) * 0.01
					if twPenalty < 0 {
						twPenalty = -twPenalty
					}
					timePenalty += twPenalty
				}
				finalScore := score + timePenalty
				if len(topK) < kTop {
					topK = append(topK, c)
					topK[len(topK)-1].delta = finalScore
				} else {
					maxIdx := 0
					for j := 1; j < len(topK); j++ {
						if topK[j].delta > topK[maxIdx].delta {
							maxIdx = j
						}
					}
					if finalScore < topK[maxIdx].delta {
						topK[maxIdx] = c
						topK[maxIdx].delta = finalScore
					}
				}
			}
			minScore := 1e100
			bestCand := -1
			for idx, c := range topK {
				if c.inserted && c.delta < minScore {
					minScore = c.delta
					bestCand = idx
				}
			}
			if bestCand >= 0 && bestCand < len(topK) {
				chosen := topK[bestCand]
				target := &dispatch.Assigns[chosen.ai]
				target.RemoveShip(total_ship + oi)
				*target = chosen.saved
				ok := target.AddShip(total_ship+oi, oris[oi], dess[oi])
				if ok {
					target.GenRoute()
					if target.Cost >= 0 {
						inserted = true
					} else {
						target.RemoveShip(total_ship + oi)
						*target = chosen.saved
						target.GenRoute()
					}
				}
			}
		}
		if !inserted {
			const maxAttempts = 8
			attempts := 0
			for ai := 0; ai < MAXASSIGNS && attempts < maxAttempts; ai++ {
				if ai >= dispatch.AssignsLen {
					dispatch.AssignsLen++
				}
				target := &dispatch.Assigns[ai]
				saved := *target
				ok := target.AddShip(total_ship+oi, oris[oi], dess[oi])
				if ok {
					target.GenRoute()
					if target.Cost >= 0 {
						inserted = true
						break
					} else {
						target.RemoveShip(total_ship + oi)
						*target = saved
						target.GenRoute()
					}
				}
				attempts++
			}
			if !inserted {
