func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	for shipIdx := 0; shipIdx < len(oris); shipIdx++ {
		bestAssignIdx := -1
		bestScore := math.MaxFloat64
		var savedBestState Assign
		savedStates := make([]Assign, dispatch.AssignsLen)
		feasibleFound := false

		timeWindowPenaltyBase := 1000.0
		if oris[shipIdx].TimeEnd > oris[shipIdx].TimeStart {
			tightness := float64(oris[shipIdx].Load) / float64(oris[shipIdx].TimeEnd-oris[shipIdx].TimeStart+1)
			timeWindowPenaltyBase += tightness * 500.0
		}

		for i := 0; i < dispatch.AssignsLen; i++ {
			savedStates[i] = dispatch.Assigns[i]
			ok := dispatch.Assigns[i].AddShip(total_ship+shipIdx, oris[shipIdx], dess[shipIdx])
