				delta := dispatch.Assigns[i].Cost - savedStates[i].Cost

				loadRisk := 0.0
				if dispatch.Assigns[i].StationCurrent.Load > 80 {
					loadRisk = float64(dispatch.Assigns[i].StationCurrent.Load) * 0.5
				}

				deadlineSlack := 0.0
				currentTime := int(savedStates[i].Cost) // approximate from previous cost
				if dess[shipIdx].TimeEnd > currentTime {
